m_syntax_basics.let_in_block:
// All M queries use let/in structure
// Each line in let is a 'step' — a named expression
// Steps are evaluated lazily (only if needed)
// 'in' specifies the final output value
let
    Step1 = someExpression,
    Step2 = transformStep1(Step1),
    Step3 = anotherTransform(Step2)
in
    Step3

m_syntax_basics.each_keyword:
// 'each' is shorthand for (_) => where _ is the implicit parameter
// These are equivalent:
Table.SelectRows(Source, each [Amount] > 100)
Table.SelectRows(Source, (_) => _[Amount] > 100)

// Access a column by name with [ColumnName] inside 'each'
// _ is the current row record

m_syntax_basics.implicit_parameter:
// _ (underscore) is the implicit parameter in 'each' expressions
// These all mean the same thing:
each _ > 0
each Number.IsPositive(_)
(x) => x > 0

m_syntax_basics.accessing_record_fields:
// Access a field in a record using square brackets
record[FieldName]
// In 'each' context, _ is the row record:
each _[Amount]
// Same as:
each [Amount]  // _ is implicit

m_syntax_basics.accessing_list_elements:
// Access element by index (zero-based)
myList{0}   // first element
myList{2}   // third element
// Access named record within a list:
myTable{[Name="Alice"]}  // row where Name = "Alice"

m_syntax_basics.error_handling:
// try/otherwise for error handling
try someExpression otherwise defaultValue
// Example:
try Number.FromText([Value]) otherwise 0

sharepoint_functions.filtering_files:
// After SharePoint.Files(), filter to specific folder:
FilteredFiles = Table.SelectRows(Source, each Text.Contains([Folder Path], "/Shared Documents/Reports/")),

// Filter to specific extension:
CSVOnly = Table.SelectRows(FilteredFiles, each [Extension] = ".csv"),

// Filter to files modified after a date:
RecentFiles = Table.SelectRows(Source, each [Date modified] >= #datetime(2024, 1, 1, 0, 0, 0))

csv_parsing.parsing_within_table:
// Parse CSV binary in-place within a table column:
ParseCSV = Table.AddColumn(FilesTable, "Data",
    each Csv.Document([Content], [Delimiter=",", Encoding=65001, QuoteStyle=QuoteStyle.None])
)

csv_parsing.promote_headers_in_each_csv:
// Promote first row to headers in each parsed table:
WithHeaders = Table.TransformColumns(ParseCSV, {
    "Data", each Table.PromoteHeaders(_, [PromoteAllScalars=true])
})

csv_parsing.skip_top_n_rows_before_headers:
// If CSV has 4 header/metadata rows before column names:
SkipRows = Table.TransformColumns(ParseCSV, {
    "Data", each
        let
            removed = Table.Skip(_, 4),          // skip first 4 rows
            promoted = Table.PromoteHeaders(removed)
        in promoted
})

SelectRows.example:
// Keep rows where Amount > 0
Table.SelectRows(Source, each [Amount] > 0)

// Keep rows where Extension is .csv
Table.SelectRows(Source, each [Extension] = ".csv")

// Multiple conditions
Table.SelectRows(Source, each [Year] = 2024 and [Region] = "EMEA")

AddColumn.example:
// Add a column squaring each value
Table.AddColumn(Source, "AmountSquared", each [Amount] * [Amount], type number)

// Add a date column from year and month
Table.AddColumn(Source, "MonthDate", each #date([Year], [Month], 1), type date)

TransformColumnTypes.example:
Table.TransformColumnTypes(Source, {
    {"Date",     type date},
    {"Amount",   Currency.Type},
    {"Quantity", Int64.Type},
    {"Name",     type text},
    {"IsActive", type logical}
})

Combine.example:
// Combine a list of tables
Table.Combine({Table1, Table2, Table3})

// Combine from a column of tables:
Table.Combine(ExpandedList[ParsedCSV])

ExpandTableColumn.example:
// Expand ParsedCSV column, keeping named columns
Table.ExpandTableColumn(ParseCSV, "ParsedCSV", {"Date", "Category", "Amount"})

// Dynamic: expand using column names from first parsed table
Table.ExpandTableColumn(ParseCSV, "ParsedCSV", Table.ColumnNames(ParseCSV{0}[ParsedCSV]))

Group.example:
// Sum Amount by Year and Month
Table.Group(Source, {"Year", "Month"}, {
    {"Total Amount", each List.Sum([Amount]), type number},
    {"Row Count",   each Table.RowCount(_), Int64.Type},
    {"Avg Amount",  each List.Average([Amount]), type number}
})

TransformColumns.example:
// Convert all text in Name column to uppercase, and parse Amount as number
Table.TransformColumns(Source, {
    {"Name",   Text.Upper,         type text},
    {"Amount", Number.FromText,    type number}
})

text_functions.Contains:
Text.Contains(text as nullable text, substring as text, [comparer as nullable function]) as nullable logical
// Example:
Text.Contains([Folder Path], "/Reports/")  // returns true/false

text_functions.Middle:
Text.Middle(text, offset, count)
// Zero-based offset. Example: extract year from 'report_2024_01.csv'
Text.Middle("report_2024_01.csv", 7, 4)  // returns "2024"

text_functions.Split:
Text.Split(text, delimiter) as list
// Returns a list of substrings
// Example: Text.Split("2024-01", "-")  // returns {"2024", "01"}
// Access element: Text.Split("2024-01", "-"){0}  // "2024"

text_functions.Trim:
Text.Trim(text, [trimChars])
// Remove leading/trailing whitespace
Text.Trim("  hello  ")  // "hello"

text_functions.PadStart:
Text.PadStart(text, count, [paddingCharacter])
// Pad with character on the left to reach count length
// Example: Text.PadStart("3", 2, "0")  // "03"
// Useful for month numbers: Text.PadStart(Text.From(5), 2, "0")  // "05"

text_functions.From:
Text.From(value, [culture])
// Convert any value to text
// Example: Text.From(2024)  // "2024"

text_functions.BetweenDelimiters:
Text.BetweenDelimiters(text, startDelimiter, endDelimiter)
// Extract text between two delimiters
// Example: Text.BetweenDelimiters("[Category]", "[", "]")  // "Category"

number_functions.FromText:
Number.FromText(text, [culture])
// Parse text as a number. Returns error if not parseable.
// Example: Number.FromText("42")  // 42

date_functions.DayOfWeek:
Date.DayOfWeek(date, [firstDayOfWeek])
// Returns 0-6. Default first day is Sunday (0).
// Date.DayOfWeek(#date(2024, 1, 15), Day.Monday)  // 0 = Monday

date_functions.From:
Date.From(value)
// Convert datetime or text to date
// Example: Date.From(DateTime.LocalNow())

date_functions.ToText:
Date.ToText(date, [options])
// Format date as text using .NET format strings
// Example: Date.ToText(#date(2024, 3, 15), "MMMM YYYY")  // "March 2024"
// Example: Date.ToText(#date(2024, 3, 15), "MM-dd-yyyy")  // "03-15-2024"
// Example: Date.ToText(#date(2024, 3, 15), "MMM")        // "Mar"
// For locale: Date.ToText(date, [Format="MMMM", Culture="en-US"])

date_functions.LocalNow:
DateTime.LocalNow() as datetime
// Current date and time in local timezone
// Use Date.From(DateTime.LocalNow()) to get today's date

date_functions.List_Dates:
List.Dates(start as date, count as number, step as duration) as list
// Generate a list of dates
// Example: all dates in Jan 2024
List.Dates(#date(2024, 1, 1), 31, #duration(1, 0, 0, 0))
// All dates from 2023-01-01 to today:
List.Dates(
    #date(2023, 1, 1),
    Duration.Days(Date.From(DateTime.LocalNow()) - #date(2023, 1, 1)) + 1,
    #duration(1, 0, 0, 0)
)

date_functions.Duration_Days:
Duration.Days(duration as duration) as number
// Get number of days from a duration
// Example: Duration.Days(#date(2024,12,31) - #date(2024,1,1))  // 365

date_functions.StartOfMonth:
Date.StartOfMonth(date)
// Returns the first day of the month
// Example: Date.StartOfMonth(#date(2024, 3, 15))  // #date(2024, 3, 1)

date_functions.EndOfMonth:
Date.EndOfMonth(date)
// Returns the last day of the month
// Example: Date.EndOfMonth(#date(2024, 2, 1))  // #date(2024, 2, 29)

record_functions.Field:
Record.Field(record, fieldName)
// Get field value by name (dynamic, useful when name is a variable)
// Example: Record.Field([Name="Alice", Age=30], "Name")  // "Alice"

complete_monthly_template.query:
// ============================================================
// Power Query M Template: Monthly SharePoint CSV Combiner
// Filename convention: report_YYYY_MM.csv
// SharePoint site: update SiteUrl
// Folder path filter: update FolderPath
// CSV column names: update ColumnNames and TypeCasting step
// ============================================================
let
    // ── CONFIG ─────────────────────────────────────────────
    SiteUrl    = "https://contoso.sharepoint.com/sites/MySite",
    FolderPath = "/Shared Documents/Monthly-Reports/",
    // Prefix before YYYY in filename: "report_" is 7 chars
    YearOffset  = 7,
    MonthOffset = 12,

    // ── 1. CONNECT ────────────────────────────────────────
    RawFiles = SharePoint.Files(SiteUrl, [ApiVersion=15]),

    // ── 2. FILTER TO FOLDER ───────────────────────────────
    InFolder = Table.SelectRows(RawFiles,
        each Text.Contains([Folder Path], FolderPath)),

    // ── 3. CSV FILES ONLY ─────────────────────────────────
    CSVFiles = Table.SelectRows(InFolder,
        each [Extension] = ".csv"
        and not Text.StartsWith([Name], "~")  // skip temp files
    ),

    // ── 4. ADD FILENAME COLUMN ────────────────────────────
    WithFilename = Table.AddColumn(CSVFiles, "SourceFile", each [Name], type text),

    // ── 5. EXTRACT YEAR ───────────────────────────────────
    WithYear = Table.AddColumn(WithFilename, "FileYear",
        each try Number.FromText(Text.Middle([SourceFile], YearOffset, 4)) otherwise null,
        Int64.Type),

    // ── 6. EXTRACT MONTH ──────────────────────────────────
    WithMonth = Table.AddColumn(WithYear, "FileMonth",
        each try Number.FromText(Text.Middle([SourceFile], MonthOffset, 2)) otherwise null,
        Int64.Type),

    // ── 7. DROP FILES WITH BAD NAMES ──────────────────────
    ValidFiles = Table.SelectRows(WithMonth,
        each [FileYear] <> null and [FileMonth] <> null),

    // ── 8. PARSE EACH CSV ─────────────────────────────────
    Parsed = Table.AddColumn(ValidFiles, "_Data",
        each Csv.Document([Content], [
            Delimiter  = ",",
            Columns    = null,
            Encoding   = 65001,
            QuoteStyle = QuoteStyle.Csv
        ])
    ),

    // ── 9. PROMOTE HEADERS ────────────────────────────────
    Headers = Table.TransformColumns(Parsed, {
        "_Data", each Table.PromoteHeaders(_, [PromoteAllScalars=true])
    }),

    // ── 10. GET COLUMN NAMES FROM FIRST FILE ──────────────
    SampleCols = Table.ColumnNames(Headers{0}[_Data]),

    // ── 11. EXPAND ALL ROWS ───────────────────────────────
    Expanded = Table.ExpandTableColumn(Headers, "_Data", SampleCols),

    // ── 12. BUILD DATE COLUMN ────────────────────────────
    WithDate = Table.AddColumn(Expanded, "MonthDate",
        each try #date([FileYear], [FileMonth], 1) otherwise null,
        type date),

    // ── 13. REMOVE CONNECTOR METADATA COLUMNS ─────────────
    Trimmed = Table.RemoveColumns(WithDate, {
        "Content", "Extension", "Date accessed",
        "Date modified", "Date created", "Attributes", "Folder Path"
    }),

    // ── 14. CAST TYPES ────────────────────────────────────
    // Update column names and types to match your CSV schema
    Typed = Table.TransformColumnTypes(Trimmed, {
        {"SourceFile",  type text},
        {"FileYear",    Int64.Type},
        {"FileMonth",   Int64.Type},
        {"MonthDate",   type date}
        // Add your CSV columns here:
        // {"Category",   type text},
        // {"Amount",     Currency.Type},
        // {"Quantity",   Int64.Type}
    })
in
    Typed
